template:
{{ define "devops-agent-payload" }}
{{- $alert := index .Alerts 0 -}}
{{- $ns := or (index $alert.Labels "exported_namespace") (index $alert.Labels "namespace") -}}
{
  "eventType": "incident",
  "incidentId": "{{ $alert.Fingerprint }}",
  "action": {{ if eq .Status "firing" }}"created"{{ else }}"resolved"{{ end }},
  "priority": {{ with (index $alert.Labels "severity") }}{{ if eq . "critical" }}"CRITICAL"{{ else if eq . "high" }}"HIGH"{{ else if eq . "warning" }}"MEDIUM"{{ else if eq . "info" }}"LOW"{{ else }}"MINIMAL"{{ end }}{{ else }}"HIGH"{{ end }},
  "title": "{{ $alert.Labels.alertname }}",
  "description": "{{ if $alert.Annotations.summary }}{{ $alert.Annotations.summary }}{{ else }}{{ $alert.Annotations.description }}{{ end }}",
  "timestamp": "{{ $alert.StartsAt }}",
  "service": "{{ $ns }}",
  "data": {
    "pod": "{{ index $alert.Labels "pod" }}",
    "container": "{{ index $alert.Labels "container" }}",
    "namespace": "{{ $ns }}",
    "node": "{{ index $alert.Labels "node" }}",
    "reason": "{{ index $alert.Labels "reason" }}",
    "cluster": "{{ index $alert.Labels "cluster" }}",
    "generatorURL": "{{ $alert.GeneratorURL }}"
  }
}
{{ end }}
